import React, { useState } from "react";
import "../styles/GeneralChat.css";

const greetings = ["hi", "hello", "hey", "hai", "thanks", "thank"];

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hello. I'm glad you reached out today. How are you feeling right now?"
    }
  ]);
  const [input, setInput] = useState("");

  const therapistReply = (userText, previousMessages) => {
    const text = userText.toLowerCase().trim();
    const lastMessage = previousMessages.length > 0 ? previousMessages[previousMessages.length - 2]?.text.toLowerCase() || "" : "";

    // Extract key emotions/topics from user message for personalization
    const emotions = {
      scared: text.includes("scared") || text.includes("fear"),
      stressed: text.includes("stress") || text.includes("pressure"),
      overwhelmed: text.includes("overwhelm") || text.includes("too much"),
      anxious: text.includes("anxious") || text.includes("anxiety"),
      sad: text.includes("sad") || text.includes("depressed"),
      angry: text.includes("angry") || text.includes("frustrated"),
      tired: text.includes("tired") || text.includes("exhausted"),
      alone: text.includes("alone") || text.includes("isolated") || text.includes("myself")
    };

    const topics = {
      exams: text.includes("exam") || text.includes("test"),
      study: text.includes("study") || text.includes("school"),
      work: text.includes("work") || text.includes("job"),
      family: text.includes("family") || text.includes("parent") || text.includes("mother") || text.includes("father"),
      sleep: text.includes("sleep") || text.includes("tired"),
      relationships: text.includes("friend") || text.includes("partner") || text.includes("girlfriend") || text.includes("boyfriend"),
      nothing: text.includes("nothing") || text.includes("no") || text.includes("haven't")
    };

    // Greetings
    if (["hi", "hello", "hey", "hai"].some(g => text === g)) {
      return "Hello. I'm glad you reached out today. How are you feeling right now?";
    }

    // User says they haven't tried anything / no strategies
    if (topics.nothing && (text.includes("tried") || text.includes("nothing"))) {
      return "That's completely okay. Sometimes when we're overwhelmed, it's hard to even think of what to try. Let's explore together. What do you think would feel manageable for you right now - something small that might help even a little?";
    }

    // Contextual responses based on previous question
    if (lastMessage.includes("strategies") && !topics.nothing) {
      return "It sounds like you've tried some things. What has helped you even a little bit? And what do you wish worked better?";
    }

    // Scared/Fear responses
    if (emotions.scared) {
      return `I hear that you're feeling scared. That's a very real emotion. Can you tell me what specifically you're most afraid of right now? Sometimes understanding the root of our fear helps us feel less overwhelmed by it.`;
    }

    // Exam/test anxiety
    if (topics.exams) {
      return "Exams can bring a lot of pressure and anxiety. It sounds like the upcoming exams are weighing on you. When did you start feeling this way about them? Is it the workload, worry about performance, or something else?";
    }

    // Work/job stress
    if (topics.work && !topics.study) {
      return "Work pressure can be really draining. You mention work - is it the workload itself, your relationships with colleagues, or pressure to perform that's getting to you most?";
    }

    // Family pressure
    if (topics.family) {
      return "Family expectations can be really powerful. You mentioned family - can you tell me what kind of pressure you're feeling from them? And how do you feel about those expectations?";
    }

    // Relationships
    if (topics.relationships) {
      return "Relationship dynamics can deeply affect how we feel. You brought up relationships - is there conflict, distance, or pressure there that's contributing to what you're experiencing?";
    }

    // Sleep issues
    if (topics.sleep) {
      return "Sleep is so important for our emotional and mental health. When you're not sleeping well, it can make everything feel harder. How long has this been going on, and do you notice any pattern - like when it's worse?";
    }

    // Tired/exhausted but not yet elaborated
    if (emotions.tired && !topics.exams && !topics.work && !topics.study) {
      return "It sounds like you're running on empty right now. Can you tell me - what's draining your energy most? Is it emotional stress, physical exhaustion, or a combination?";
    }

    // Overwhelmed
    if (emotions.overwhelmed) {
      return "When everything feels like too much, it's easy to not know where to start. What feels most overwhelming to you right now? Breaking it down into parts sometimes helps.";
    }

    // Anxious/Worried
    if (emotions.anxious) {
      return "Anxiety can be really uncomfortable. What are you most anxious about right now? Sometimes just naming what we're worried about makes it feel more manageable.";
    }

    // Sad/Depressed
    if (emotions.sad) {
      return "Thank you for trusting me with that. When you say you're feeling sad, how long has it been like this? And have you noticed what makes it better or worse?";
    }

    // Angry/Frustrated
    if (emotions.angry) {
      return "Anger often masks something deeper - hurt, fear, or feeling unheard. What specifically happened that made you feel this way? And what would help right now?";
    }

    // Alone/Isolated
    if (emotions.alone) {
      return "Feeling alone can be one of the most painful experiences. Do you feel isolated because you're keeping things to yourself, or because you feel like no one understands? Let's talk about that.";
    }

    // Good/Fine but came to chat
    if ((text.includes("good") || text.includes("fine") || text.includes("okay")) && !emotions.scared && !emotions.stressed) {
      return "That's nice to hear that things are okay right now. Sometimes we reach out not because we're in crisis, but because we want to understand ourselves better. Is there anything you've been thinking about lately?";
    }

    // Default - more empathetic, open-ended
    return "Thank you for sharing that. I want to understand your experience better. Can you tell me more about what's making you feel this way? What's been on your mind?";
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    const botMessage = {
      sender: "bot",
      text: therapistReply(input, messages)
    };

    setMessages([...messages, userMessage, botMessage]);
    setInput("");
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2 className="chat-title">💬 Professional Therapy Chat</h2>
        <p className="chat-subtitle">A safe space to share your feelings</p>
      </div>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`message-group ${msg.sender === "user" ? "user-group" : "therapist-group"}`}
          >
            <div className="message-label">
              {msg.sender === "user" ? "You" : "Therapist"}
            </div>
            <div className={`message ${msg.sender === "user" ? "user" : "bot"}`}>
              {msg.text}
            </div>
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Share your thoughts safely..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={handleKeyPress}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
